1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	
6	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: unknown; steps: Step[] };
16	
17	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
18	
19	const basePremiumForMainItem = ({ type }: Item): number =>
20	  BASE_PREMIUM_BY_TYPE[type] ?? 0;
21	
22	const sumComponentPremiums = (components: Item[]): number => {
23	  const countByType = new Map<string, number>();
24	  for (const c of components) {
25	    countByType.set(c.type, (countByType.get(c.type) ?? 0) + 1);
26	  }
27	  let total = 0;
28	  for (const count of countByType.values()) {
29	    if (count === COMPONENT_BLOCK_SIZE) total += COMPONENT_BLOCK_PREMIUM;
30	    else total += count * COMPONENT_BASE_PREMIUM;
31	  }
32	  return total;
33	};
34	
35	const sumBasePremiums = (items: Item[]): number => {
36	  const mains = items.filter(isMainItem);
37	  const components = items.filter((i) => !isMainItem(i));
38	  const mainsSum = mains.reduce((sum, item) => sum + basePremiumForMainItem(item), 0);
39	  return mainsSum + sumComponentPremiums(components);
40	};
41	
42	const quotePremiumFor = (step: Step): { premium: number } => ({
43	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
44	});
45	
46	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
47	  results: scenario.steps.map(quotePremiumFor),
48	});
49

